        val tokenExpiry: Long
    )

    /**
     * Persist authentication credentials after successful login.
     * All data is encrypted at rest via EncryptedSharedPreferences backed by Android Keystore.
     */
    fun saveAuthCredentials(
        authToken: String,
        userId: String,
        refreshToken: String? = null,
        tokenExpiryMillis: Long = System.currentTimeMillis() + 3_600_000L // default 1 hour
    ) {
        require(authToken.isNotBlank()) { "Auth token must not be blank" }
        require(userId.isNotBlank()) { "User ID must not be blank" }

        encryptedPrefs.edit().apply {
            putString(KEY_AUTH_TOKEN, authToken)
            putString(KEY_USER_ID, userId)
            putBoolean(KEY_IS_LOGGED_IN, true)
            putLong(KEY_TOKEN_EXPIRY, tokenExpiryMillis)
            refreshToken?.let { putString(KEY_REFRESH_TOKEN, it) }
            apply()
