     */
    fun isLoggedIn(): Boolean {
        return encryptedPrefs.getBoolean(KEY_IS_LOGGED_IN, false)
    }

    /**
     * Check whether the current auth token has expired.
     */
    fun isTokenExpired(): Boolean {
        val expiry = encryptedPrefs.getLong(KEY_TOKEN_EXPIRY, 0L)
        return System.currentTimeMillis() >= expiry
    }

    /**
     * Get a snapshot of the full authentication state.
     */
    fun getAuthState(): AuthState {
        return AuthState(
            isLoggedIn = isLoggedIn(),
            userId = getUserId(),
            authToken = getAuthToken(),
            tokenExpiry = encryptedPrefs.getLong(KEY_TOKEN_EXPIRY, 0L)
        )
    }

    /**
     * Update the auth token (e.g., after a token refresh).
     */
    fun updateAuthToken(newToken: String, newExpiryMillis: Long) {
        require(newToken.isNotBlank()) { "New auth token must not be blank" }

        encryptedPrefs.edit().apply {
            putString(KEY_AUTH_TOKEN, newToken)
            putLong(KEY_TOKEN_EXPIRY, newExpiryMillis)
